	"dcterms:creator": {
		"@id": "https://github.com/mfolia",
		"@type": [
			"cwrc:NaturalPerson",
			"schema:Person"
		],
		"cwrc:hasName": "Marc Folia"
	},
	"oa:motivatedBy": "oa:describing",
	"oa:hasTarget": {
		"@id": "https://raw.githubusercontent.com/mfolia/tei/main/1.xml?note_annotation_20260510215246177#Target",
		"@type": "oa:SpecificResource",
		"oa:hasSource": {
			"@id": "https://raw.githubusercontent.com/mfolia/tei/main/1.xml",
			"@type": "dctypes:Text",
			"dc:format": "text/xml"
		},
		"oa:renderedVia": {
			"@id": "https://leaf-writer.leaf-vre.org",
			"@type": "as:Application",
			"rdfs:label": "LEAF-Writer",
			"schema:softwareVersion": "4.2.0"
		},
		"oa:hasSelector": {
			"@id": "https://raw.githubusercontent.com/mfolia/tei/main/1.xml?note_annotation_20260510215246177#Selector",
			"@type": "oa:XPathSelector",
			"rdf:value": "TEI/text/body/div/dateline/note"
		}
	},
	"oa:hasBody": {
		"@type": "cwrc:Note",
		"dc:format": "text/plain",
		"rdf:value": "Per a la datació d’aquest acte i dels dos següents s’han considerat dues possibilitats: la primera —1067—, adoptada per Devic-Vaissete i Feliu-Salrach i avalada per H. Débax, pressuposa un estil pisà en el còmput de l’any de l’Encarnació i un càlcul de l’any del regnat de Felip a partir de la coronació del rei Felip (1059); la segona —1068—, seguida per Miquel Rosell, F. L. Cheyette i G. Ammannati, suposa un còmput florentí i un càlcul de l’any del regnat de Felip a partir de la mort del seu predecessor, Enric I (1060). H. Débax, La féodalité languedocienne, p. 61, n. 248, sosté que aquests tres actes, datats el 2 de març, s’avançaren en un any a la definició dels comtes de Barcelona a Ramon Bernat i Ermengarda de l’1 de març de 1068 (doc. núm. 8), tot i que la coincidència de dates indueixi a pensar el contrari. La seva hipòtesi es basa en els arguments següents: en primer lloc, perquè per lògica aquests tres textos han d’ésser anteriors a la definició, altrament els comtes de Barcelona no haurien pogut desfer-se d’uns béns que prèviament no posseïen; perquè inclouen llistes de testimonis diferents dels de la definició; perquè és possible que fossin redactats al Llenguadoc, on els comtes de Barcelona viatjaren a final de 1066 i on es trobaven a començaments de 1067 (concretament el 5 de febrer eren a Nimes, on reberen un empenyorament del vescomte de Narbona [Devic-Vaissete, HGL, v, 546], document, de l’any vuitè de Felip, que hom pot datar de manera segura el 1067 mercès a la concordança de les nones de febrer amb la fèria II —el dilluns 5 de febrer correspon a l’any 1067—). Contràriament, G. Ammannati, Saint-Victor DI Marsiglia, p. 57, sosté que aquests tres actes foren redactats l’endemà de la definició dels comtes de Barcelona a Ramon Bernat i Ermengarda l’1 de març de 1068 (doc. núm. 8). Aquesta autora aporta proves que demostren que l’escrivà dels comtes de Barcelona Petrus datava els documents segons l’estil florentí."
	},
	"as:generator": {
		"@id": "https://leaf-writer.leaf-vre.org",
		"@type": "as:Application",
		"rdfs:label": "LEAF-Writer",
		"schema:url": "https://leaf-writer.lincsproject.ca/",
		"schema:softwareVersion": "4.2.0"
	}
}

