	"oa:hasBody": {
		"@type": "cwrc:Note",
		"dc:format": "text/plain",
		"rdf:value": "B jhhj la Carta deffinitionis et evacuationis quam fecit Raimundus Bernardi vicecomes et uxor eius Ermengardis Raimundo, comiti Barcinonensi, de tota civitate Carcassone et aliis quibusdam, ut in instrumento continetur."
	},
